async function main() {
  console.log("🌱 Seeding comprehensive ingredient database...");

  // Upsert categories
  const categoryMap: Record<string, string> = {};
  for (const cat of CATEGORIES) {
    const result = await prisma.ingredientCategory.upsert({
      where: { slug: cat.slug },
      update: cat,
      create: cat,
    });
    categoryMap[cat.slug] = result.id;
  }
  console.log(`✓ ${CATEGORIES.length} categories`);

  // Upsert ingredients
  const ALL_INGREDIENTS = [...INGREDIENTS, ...MORE_INGREDIENTS];
  let count = 0;
  for (const ing of ALL_INGREDIENTS) {
    const { categorySlug, ...data } = ing;
    const categoryId = categoryMap[categorySlug];
    if (!categoryId) { console.warn(`⚠ No category for ${ing.name}`); continue; }

    await prisma.ingredient.upsert({
      where: { slug: data.slug },
      update: { ...data, categoryId },
      create: { ...data, categoryId },
    });
    count++;
  }

  console.log(`✓ ${count} ingredients seeded`);
  console.log("✅ Done");
}

main()
  .catch((e) => { console.error(e); process.exit(1); })
  .finally(() => prisma.$disconnect());
